/**
 * @typedef {object} State
 * @property {number} count - The number of special indices achieved.
 * @property {number} cost - The minimum total operations required to achieve this count.
 */

/**
 * Compares two states. Returns true if State A is strictly better than State B.
 * Better means higher count, or same count with lower cost.
 * @param {State} A 
 * @param {State} B 
 * @returns {boolean} True if A is better than B.
 */
function isBetter(A: State, B: State): boolean {
    if (A.count > B.count) return true;
    if (A.count === B.count && A.cost < B.cost) return true;
    return false;
}

/**
 * Solves the problem by using Dynamic Programming.
 * We track two states for each index i (1 <= i <= n-2):
 * 1. DP_in[i]: Minimum cost to achieve the best possible count ending with i being a peak.
 * 2. DP_out[i]: Minimum cost to achieve the best possible count ending with i NOT being a peak.
 * 
 * @param {number[]} nums The input array.
 * @returns {number} The minimum total operations required.
 */
function solve(nums: number[]): number {
    const n = nums.length;
    if (n < 3) {
        return 0;
    }

    // Use a sentinel state representing impossible/worst state
    const INF_COST = Number.MAX_SAFE_INTEGER;
    const WORST_STATE: State = { count: -1, cost: INF_COST };

    // DP arrays size N. We only use indices 1 to N-2.
    const DP_in: State[] = Array(n).fill(WORST_STATE);
    const DP_out: State[] = Array(n).fill(WORST_STATE);

    // --- Base Case: i = 1 ---
    const i = 1;
    // Cost to make nums[1] a peak: max(nums[0], nums[2]) + 1 - nums[1]
    const cost1 = Math.max(0, Math.max(nums[i - 1], nums[i + 1]) + 1 - nums[i]);

    // If i=1 is chosen as a peak
    DP_in[i] = { count: 1, cost: cost1 };
    // If i=1 is not chosen
    DP_out[i] = { count: 0, cost: 0 };

    // --- DP Transitions: i = 2 to N-2 ---
    for (let i = 2; i <= n - 2; i++) {
        // 1. Calculate Cost C_i if i is chosen as a peak
        // Neighbors are i-1 and i+1. Since we enforce non-adjacency, neighbors are not peaks.
        // We assume neighbors remain at their original value for minimum cost calculation.
        const cost_i = Math.max(0, Math.max(nums[i - 1], nums[i + 1]) + 1 - nums[i]);

        // 2. DP_out[i]: i is NOT chosen. We take the best state from i-1.
        let best_prev: State;
        if (isBetter(DP_in[i - 1], DP_out[i - 1])) {
            best_prev = DP_in[i - 1];
        } else {
            best_prev = DP_out[i - 1];
        }
        DP_out[i] = best_prev;

        // 3. DP_in[i]: i IS chosen. Must transition from DP_out[i-1] (since i-1 cannot be a peak).
        if (DP_out[i - 1].count !== -1) {
            const new_count = DP_out[i - 1].count + 1;
            const new_cost = DP_out[i - 1].cost + cost_i;
            DP_in[i] = { count: new_count, cost: new_cost };
        }
    }

    // --- Final Result ---
    let final_result: State;
    if (isBetter(DP_in[n - 2], DP_out[n - 2])) {
        final_result = DP_in[n - 2];
    } else {
        final_result = DP_out[n - 2];
    }

    return final_result.cost;
}
