function isBetter(A: [number, number], B: [number, number]): boolean {
    const [CA, CostA] = A;
    const [CB, CostB] = B;

    // Maximize count first
    if (CA !== CB) {
        return CA > CB;
    }
    // If counts are equal, minimize cost
    return CostA < CostB;
}

function solve(nums: number[]): number {
    const N = nums.length;
    if (N < 3) {
        return 0;
    }

    // DP state: [count, cost]
    // We consider indices i = 1 to N-2

    // DP_NO_PEAK[i]: Optimal state considering indices up to i, where i is NOT a peak.
    // DP_PEAK[i]: Optimal state considering indices up to i, where i IS a peak.

    // Initialize DP tables of size N. We only use indices 1 to N-2.
    // We use a sentinel value for initialization representing an unreachable/worse state.
    const WORST_STATE: [number, number] = [-1, Infinity]; 
    const DP_NO_PEAK: Array<[number, number]> = Array(N).fill(null).map(() => [...WORST_STATE]);
    const DP_PEAK: Array<[number, number]> = Array(N).fill(null).map(() => [...WORST_STATE]);

    // Base Case i = 1
    const i = 1;

    // Cost V(1) required if nums[1] is a peak
    // V(i) = max(0, max(nums[i-1], nums[i+1]) + 1 - nums[i])
    const V1 = Math.max(0, Math.max(nums[0], nums[2]) + 1 - nums[1]);

    // i=1 is not a peak
    DP_NO_PEAK[1] = [0, 0];
    // i=1 is a peak
    DP_PEAK[1] = [1, V1];

    // Iterate i from 2 up to N-2
    for (let i = 2; i <= N - 2; i++) {
        // Calculate V(i)
        const Vi = Math.max(0, Math.max(nums[i - 1], nums[i + 1]) + 1 - nums[i]);

        // 1. Calculate DP_NO_PEAK[i]
        // i is not a peak. We take the best result from i-1 (whether i-1 was peak or not).
        const S1 = DP_NO_PEAK[i - 1];
        const S2 = DP_PEAK[i - 1];

        if (isBetter(S1, S2)) {
            DP_NO_PEAK[i] = S1;
        } else {
            DP_NO_PEAK[i] = S2;
        }

        // 2. Calculate DP_PEAK[i]
        // i is a peak, so i-1 MUST NOT be a peak. We transition from DP_NO_PEAK[i-1].
        const [C_prev, Cost_prev] = DP_NO_PEAK[i - 1];

        if (C_prev >= 0) { // Ensure the predecessor state was reachable
            const newCount = C_prev + 1;
            const newCost = Cost_prev + Vi;
            DP_PEAK[i] = [newCount, newCost];
        }
    }

    // Final Result is the best state found at index N-2
    const finalNoPeak = DP_NO_PEAK[N - 2];
    const finalPeak = DP_PEAK[N - 2];

    let finalState: [number, number];

    // Handle the case where N-2 might be unreachable (though unlikely given N>=3)
    if (finalNoPeak[0] === -1 && finalPeak[0] === -1) {
        return 0;
    } else if (finalNoPeak[0] === -1) {
        finalState = finalPeak;
    } else if (finalPeak[0] === -1) {
        finalState = finalNoPeak;
    } else if (isBetter(finalNoPeak, finalPeak)) {
        finalState = finalNoPeak;
    } else {
        finalState = finalPeak;
    }

    return finalState[1];
}
