function solve(nums: number[]): number {
    const N = nums.length;
    if (N < 3) {
        return 0;
    }

    // N' is the number of indices where a peak can potentially occur: {1, 2, ..., N-2}
    const N_prime = N - 2;
    // K_max is the maximum number of non-adjacent peaks possible
    const K_max = Math.ceil(N_prime / 2);

    // 1. Precalculate cost C_i for each potential peak index i (1 <= i <= N-2)
    // C[i] stores the cost for index i. We use 1-based indexing conceptually, 
    // so we size the array N-1 and ignore index 0.
    const costs: number[] = new Array(N); 

    for (let i = 1; i <= N - 2; i++) {
        // C_i = max(0, max(nums[i-1], nums[i+1]) + 1 - nums[i])
        const required_height = Math.max(nums[i - 1], nums[i + 1]) + 1;
        const cost = Math.max(0, required_height - nums[i]);
        costs[i] = cost;
    }

    // 2. Determine the minimum cost based on the structure of the maximal independent sets.

    if (N_prime % 2 !== 0) {
        // N' is odd. K_max = (N'+1)/2. Only the pattern {1, 3, 5, ..., N-2} achieves this density.
        let totalCost = 0;
        for (let i = 1; i <= N_prime; i += 2) {
            totalCost += costs[i];
        }
        return totalCost;
    } else {
        // N' is even. K_max = N'/2. We compare two canonical patterns:

        // Pattern 1: {1, 3, 5, ..., N-3} (Starts at 1)
        let costOdd = 0;
        for (let i = 1; i <= N_prime - 1; i += 2) {
            costOdd += costs[i];
        }

        // Pattern 2: {2, 4, 6, ..., N-2} (Starts at 2)
        let costEven = 0;
        for (let i = 2; i <= N_prime; i += 2) {
            costEven += costs[i];
        }

        // The minimum cost is the smaller of the two.
        return Math.min(costOdd, costEven);
    }
}
